import {
  COLOR_VISION_MODES,
  RESPONSE_MODES,
  type AccessibilitySettings,
  type ColorVisionMode,
  type LanguagePreference,
  type ResponseMode,
} from '@/profile/types';
import { useProfile } from '@/profile/useProfile';
