/** Boolean comfort settings (everything except the colorVision selector). */
type ToggleKey = Exclude<keyof AccessibilitySettings, 'colorVision'>;

interface ToggleRow {
  readonly key: ToggleKey;
  readonly label: string;
  readonly description: string;
}

/**
 * Accessibility list rows, labeled by EFFECT never by condition (spec 5.6).
 * Reuses the prototype's toggle-row template for our six real comfort settings.
 */
const TOGGLES: readonly ToggleRow[] = [
  { key: 'readerFont', label: 'Reader Font', description: 'Gamitin ang OpenDyslexic font' },
  { key: 'highContrast', label: 'High Contrast', description: 'Dagdagan ang kaibahan ng mga kulay' },
  { key: 'largeText', label: 'Larger Text', description: 'Palakihin ang lahat ng teksto' },
  { key: 'focusMode', label: 'Focus Mode', description: 'Bawasan ang mga abala sa screen' },
  { key: 'lowMotion', label: 'Reduce Motion', description: 'Pigilan ang mga animations' },
];

const COLOR_VISION_LABEL: Record<ColorVisionMode, string> = {
  standard: 'Standard',
  deuteranopia: 'Deuteranopia',
  protanopia: 'Protanopia',
  tritanopia: 'Tritanopia',
};

/** "Paraan ng Pagpapaliwanag" segmented control — one segment per response mode. */
const RESPONSE_MODE_LABEL: Record<ResponseMode, string> = {
  visual: 'Visual',
  auditory: 'Boses',
  reading: 'Teksto',
  kinesthetic: 'Galaw',
  mixed: 'Mixed',
};

const LANGUAGE_LABEL: Record<LanguagePreference, string> = {
  tagalog: 'Tagalog',
  taglish: 'Taglish',
  english: 'English',
};

/** Avatar placeholder occupying the same 80x80 circular slot as the prototype mascot. */
const AVATAR_PLACEHOLDER_URI =
  'https://lh3.googleusercontent.com/aida-public/AB6AXuBqwqGB5DmpaF6AyNLDmewaRbkTsB776lWri3eWRBHVjfZYQhSBy3jxePTMfwfLRvwDjOZjG-3QPVscbbMEQtneJfuwbJDSykE_PVQSTfApfWWnD9MyyWPaD08BuRNXDh7jP9dln1sA_nbt6VCXhaWcOaTBHL6rIHaGl94ujywV1sn9FNiUcaHcDaJ-j27pZ4Z_Ixy10HpmfSdZCezviiZT26fQ3AFw9vfWa5p2rVmQf4AgD7LzIskedLHAQj5EGqvW8c_FpBVpN_A';

/**
 * Profile tab ("Ako"). Strict 1:1 port of the web prototype's Settings view,
 * recolored to the dark "Tambayan" palette. Wires the live Learning Profile
 * (response mode + the six accessibility comfort settings) and surfaces streak +
 * badge progress in the profile header.
 */
export default function ProfileScreen() {
  const { profile, update, updateAccessibility, reset } = useProfile();
  const { streak, badges } = useStreaks();
  const tabBarScroll = useTabBarScroll();

  const settings = profile.accessibilitySettings;
  const currentStreak = streak?.currentStreak ?? 0;
  const earnedBadges = badges.filter((badge) => badge.earnedAt !== null).length;

  const summaryParts: string[] = [`Grade ${profile.gradeLevel}`];
  if (profile.subject) {
    summaryParts.push(profile.subject);
  }
  summaryParts.push(LANGUAGE_LABEL[profile.languagePreference]);
  const summary = `Mag-aaral: ${summaryParts.join('  •  ')}`;

  const setToggle = <K extends ToggleKey>(key: K, value: boolean): void => {
    void updateAccessibility({ [key]: value } as Pick<AccessibilitySettings, K>);
  };

  const cycleColorVision = (): void => {
    const index = COLOR_VISION_MODES.indexOf(settings.colorVision);
    const next = COLOR_VISION_MODES[(index + 1) % COLOR_VISION_MODES.length];
    void updateAccessibility({ colorVision: next });
  };

  const selectResponseMode = (mode: ResponseMode): void => {
    if (mode !== profile.responseMode) {
      void update({ responseMode: mode });
    }
  };

  return (
    <SafeAreaView edges={['top']} style={styles.safe}>
      {/* TopBar -> in-screen header (back button omitted: this is a tab root). */}
      <View style={styles.header}>
        <View style={styles.headerSpacer} />
        <ThemedText
          variant="title"
          color={colors.accentPrimary}
          center
          style={[styles.headerTitle, styles.bold]}
        >
          Ako
        </ThemedText>
        <View style={styles.headerSpacer} />
      </View>

      <ScrollView
        contentContainerStyle={styles.scrollContent}
        showsVerticalScrollIndicator={false}
        onScroll={tabBarScroll.onScroll}
        scrollEventThrottle={tabBarScroll.scrollEventThrottle}
      >
        {/* Page Header */}
        <View style={styles.pageHeader}>
          <View style={styles.avatarWrap}>
            <Image
              source={{ uri: AVATAR_PLACEHOLDER_URI }}
              style={styles.avatarImage}
              resizeMode="cover"
            />
          </View>
          <View style={styles.pageHeaderInfo}>
            <ThemedText variant="h1" style={styles.extrabold}>
              Mga Setting
            </ThemedText>
            <ThemedText variant="bodySmall" color={colors.textSecondary} style={styles.summary}>
              {summary}
            </ThemedText>
            <View style={styles.statRow}>
              <View style={styles.stat}>
                <Ionicons name="flame" size={16} color={colors.accentPrimary} />
                <ThemedText variant="caption" color={colors.accentPrimary}>
                  {currentStreak}-araw na streak
                </ThemedText>
              </View>
              <View style={styles.stat}>
                <Ionicons name="ribbon" size={16} color={colors.accentPrimary} />
                <ThemedText variant="caption" color={colors.accentPrimary}>
                  {earnedBadges} badge
                </ThemedText>
              </View>
            </View>
          </View>
        </View>

        {/* Sync Action (visual; remote sync is not part of the offline-first MVP). */}
        <Pressable style={styles.syncButton} accessibilityRole="button" onPress={() => {}}>
          <ThemedText variant="button" color={colors.accentPrimary}>
            I-sync ang Progress
          </ThemedText>
          <Ionicons name="chevron-forward" size={20} color={colors.accentPrimary} />
        </Pressable>

        {/* Group 1: Paraan ng Pagpapaliwanag (response mode) */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <ThemedText variant="title" style={styles.bold}>
              Paraan ng Pagpapaliwanag
            </ThemedText>
            <ThemedText variant="caption" color={colors.textSecondary} style={styles.sectionSubtitle}>
              Paano mo gustong matuto?
            </ThemedText>
          </View>
          <View style={styles.sectionBody}>
            <View style={styles.segmented}>
              {RESPONSE_MODES.map((mode) => {
                const active = profile.responseMode === mode;
                return (
                  <Pressable
                    key={mode}
                    accessibilityRole="button"
                    accessibilityState={{ selected: active }}
                    onPress={() => selectResponseMode(mode)}
                    style={[styles.segment, active && styles.segmentActive]}
                  >
                    <ThemedText
                      variant="label"
                      color={active ? colors.textOnAccent : colors.textSecondary}
                    >
                      {RESPONSE_MODE_LABEL[mode]}
                    </ThemedText>
                  </Pressable>
                );
              })}
            </View>
          </View>
        </View>

        {/* Group 2: Accessibility */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <ThemedText variant="title" style={styles.bold}>
              Accessibility
            </ThemedText>
            <ThemedText variant="caption" color={colors.textSecondary} style={styles.sectionSubtitle}>
              Ibagay ang Suri sa iyong pangangailangan
            </ThemedText>
          </View>

          <View style={styles.list}>
            {TOGGLES.map((row, index) => (
              <View key={row.key} style={[styles.row, index > 0 && styles.rowDivided]}>
                <View style={styles.rowText}>
                  <ThemedText variant="title">{row.label}</ThemedText>
                  <ThemedText variant="caption" color={colors.textSecondary} style={styles.rowDesc}>
                    {row.description}
                  </ThemedText>
                </View>
                <Switch
                  value={settings[row.key]}
                  onValueChange={(value) => setToggle(row.key, value)}
                  trackColor={{ false: colors.surfaceAlt, true: colors.accentPrimaryDim }}
                  thumbColor={settings[row.key] ? colors.accentPrimary : colors.textMuted}
                  ios_backgroundColor={colors.surfaceAlt}
                />
              </View>
            ))}

            {/* Color Vision (cycles through the colorblind-safe palettes on tap). */}
            <Pressable
              accessibilityRole="button"
              accessibilityLabel={`Color Vision: ${COLOR_VISION_LABEL[settings.colorVision]}. Tap to change.`}
              onPress={cycleColorVision}
              style={[styles.row, styles.rowDivided]}
            >
              <View style={styles.rowText}>
                <ThemedText variant="title">Color Vision</ThemedText>
                <ThemedText variant="caption" color={colors.textSecondary} style={styles.rowDesc}>
                  Ibagay ang mga kulay para sa color blindness
                </ThemedText>
              </View>
              <View style={styles.rowControl}>
                <View style={styles.pill}>
                  <ThemedText variant="label" color={colors.textPrimary}>
                    {COLOR_VISION_LABEL[settings.colorVision]}
                  </ThemedText>
                </View>
                <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
              </View>
            </Pressable>
          </View>
        </View>

        {/* Hidden Dev Tools (renders only in __DEV__) — must be the last child. */}
        <DevTools />
      </ScrollView>
    </SafeAreaView>
  );
}

